import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Calendar, Share2, Sparkles, AlertCircle, Bookmark, ThumbsUp, MessageSquare, Loader2, List, ExternalLink, Send, Check, ChevronLeft, Home, MoreHorizontal } from 'lucide-react';
import Sidebar from '../components/Sidebar';
import { summarizeArticle } from '../services/geminiService';
import { NewsService } from '../services/newsService';
import { Article } from '../types';
import SEO from '../components/SEO';

interface Comment {
  id: number;
  author: string;
  text: string;
  time: string;
  avatar: string;
  likes: number;
}

const ArticleDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [scrollY, setScrollY] = useState(0);
  const [article, setArticle] = useState<Article | null>(null);
  const [pageLoading, setPageLoading] = useState(true);

  const [likes, setLikes] = useState(0);
  const [isLiked, setIsLiked] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [showComments, setShowComments] = useState(false);

  const [commentText, setCommentText] = useState('');
  const MAX_CHARS = 500;

  const [comments, setComments] = useState<Comment[]>([]);
  const [showShareTooltip, setShowShareTooltip] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const loadArticle = async () => {
      setPageLoading(true);
      if (id) {
        const found = await NewsService.getArticleById(id);
        setArticle(found || null);
        setLikes(Math.floor(Math.random() * 20));
      }
      setPageLoading(false);
    };
    loadArticle();
  }, [id]);

  const [summary, setSummary] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSummarize = async () => {
    if (!article) return;
    setLoading(true);
    setError(null);
    try {
        const contentToSummarize = article.content || article.excerpt || article.title;
        const fullTextContext = `Title: ${article.title}. Content: ${contentToSummarize}. Please provide a 3-bullet point summary focusing on key facts.`;
        const result = await summarizeArticle(fullTextContext);
        setSummary(result);
    } catch (e) {
        setError("Could not generate summary.");
    } finally {
        setLoading(false);
    }
  };

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const toggleLike = () => {
    if (isLiked) {
        setLikes(prev => prev - 1);
        setIsLiked(false);
    } else {
        setLikes(prev => prev + 1);
        setIsLiked(true);
    }
  };

  const toggleSave = () => {
    setIsSaved(!isSaved);
  };

  const handleShare = async () => {
    if (navigator.share) {
        try {
            await navigator.share({
                title: article?.title,
                text: article?.excerpt,
                url: window.location.href,
            });
        } catch (err) {
            console.log('Share canceled');
        }
    } else {
        navigator.clipboard.writeText(window.location.href);
        setShowShareTooltip(true);
        setTimeout(() => setShowShareTooltip(false), 2000);
    }
  };

  const handleSubmitComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;

    const newComment: Comment = {
        id: Date.now(),
        author: 'Guest User',
        text: commentText,
        time: 'Just now',
        avatar: 'G',
        likes: 0
    };

    setComments([newComment, ...comments]);
    setCommentText('');
  };

  if (pageLoading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
         <Loader2 className="w-10 h-10 text-kph-red animate-spin" />
      </div>
    );
  }

  if (!article) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-8 text-center">
        <SEO title="Article Not Found | KPH News" description="The requested article could not be found." />
        <h2 className="text-3xl font-bold text-kph-charcoal mb-4">Article Not Found</h2>
        <a href="/" className="bg-kph-red text-white px-6 py-3 rounded-lg font-bold hover:bg-red-900 transition">Go Home</a>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen pb-24 lg:pb-12 animate-fade-in relative">
        <SEO 
          title={`${article.title} | KPH News`} 
          description={article.excerpt}
          image={article.imageUrl}
          imageAlt={article.title}
          type="article"
        />

        <div className="absolute top-4 left-4 z-20 lg:hidden">
            <button onClick={() => navigate(-1)} className="bg-white/90 backdrop-blur text-kph-charcoal p-2 rounded-full shadow-md">
                <ChevronLeft size={24} />
            </button>
        </div>

        <div className="relative h-[300px] lg:h-[500px] w-full overflow-hidden">
            <img 
                src={article.imageUrl} 
                alt={article.title} 
                className="w-full h-full object-cover"
                style={{ transform: `translateY(${scrollY * 0.5}px)` }} 
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-black/10"></div>

            <div 
                className="absolute bottom-0 left-0 w-full container mx-auto px-4 lg:px-8 pb-8 lg:pb-16 animate-slide-up"
                style={{ opacity: Math.max(0, 1 - scrollY / 300) }}
            >
                <div className="flex items-center space-x-3 mb-3 lg:mb-6">
                    <span className="bg-kph-red text-white px-3 py-1 text-[10px] lg:text-xs font-bold uppercase rounded">{article.category}</span>
                    <span className="text-gray-300 text-xs lg:text-sm">{article.readTime}</span>
                </div>
                <h1 className="text-2xl lg:text-5xl font-bold text-white mb-4 lg:mb-8 max-w-5xl leading-tight font-serif">{article.title}</h1>
            </div>
        </div>

        <div className="container mx-auto px-4 lg:px-8 py-8 lg:py-12 relative -mt-6 lg:-mt-8 z-10">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                <div className="lg:col-span-8 bg-white rounded-t-3xl lg:rounded-3xl p-6 lg:p-0">
                    <div id="ai-summary" className="bg-purple-50 border-2 border-purple-200 rounded-2xl p-6 mb-10">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="flex items-center text-purple-900 font-bold text-lg">
                                <Sparkles size={20} className="text-purple-600 mr-2" /> AI Smart Summary
                            </h3>
                            {!summary && !loading && (
                                <button onClick={handleSummarize} className="text-xs font-bold bg-purple-600 text-white px-5 py-2.5 rounded-full">Generate</button>
                            )}
                        </div>
                        {loading && <div className="text-purple-600 text-sm animate-pulse">Analyzing content...</div>}
                        {summary && <div className="prose prose-sm text-purple-900 bg-white/60 p-5 rounded-xl border border-purple-100 whitespace-pre-line">{summary}</div>}
                    </div>

                    <div className="prose prose-lg max-w-none text-gray-700 leading-relaxed font-serif">
                        <p className="lead text-lg lg:text-2xl font-medium mb-8 text-kph-charcoal font-sans border-l-4 border-kph-red pl-6 py-1">{article.excerpt}</p>
                        <div id="key-developments">
                             {article.content ? (
                                <div dangerouslySetInnerHTML={{ __html: article.content.replace(/\n/g, '<br/><br/>') }} />
                             ) : (
                                <p>Full details are currently unavailable for this story.</p>
                             )}
                        </div>
                    </div>

                    <div className="mt-12">
                        <h3 className="text-xl font-bold text-kph-charcoal mb-8">Discussion</h3>
                        <form onSubmit={handleSubmitComment} className="mb-12">
                            <textarea 
                                value={commentText}
                                onChange={(e) => setCommentText(e.target.value)}
                                maxLength={MAX_CHARS}
                                placeholder="Share your thoughts..." 
                                className="w-full bg-gray-50 border border-gray-200 rounded-xl p-4 min-h-[120px]"
                            />
                            <button type="submit" className="mt-3 bg-kph-charcoal text-white px-6 py-2.5 rounded-lg text-sm font-bold">Post Comment</button>
                        </form>
                        <div className="space-y-8">
