const Home: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [globalAlert, setGlobalAlert] = useState<GlobalAlert | null>(null);

  const fetchNews = async () => {
    setLoading(true);
    setError(null);
    try {
      const alertConfig = AdminService.getGlobalAlert();
      if (alertConfig && alertConfig.enabled) {
          setGlobalAlert(alertConfig);
      }

      const data = await NewsService.getLatestNews('General');

      const featuredIds = AdminService.getFeaturedArticleIds();
      if (featuredIds.length > 0) {
         const topFeatureId = featuredIds[0];
         const featureIdx = data.findIndex(a => a.id === topFeatureId);
         if (featureIdx > 0) {
            const item = data.splice(featureIdx, 1)[0];
            data.unshift(item);
         }
      }

      setArticles(data);
    } catch (err: any) {
      console.error("Failed to load news", err);
      setError("Failed to load news. Please check your internet connection.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchNews();
  }, []);

  const GlobalAlertBanner = () => {
     if (!globalAlert) return null;

     const colors = {
        info: 'bg-blue-600',
        warning: 'bg-yellow-500',
        critical: 'bg-red-600'
     };

     return (
        <div className={`${colors[globalAlert.type]} text-white px-4 py-3 flex items-center justify-center relative animate-slide-down shadow-lg z-50`}>
           <div className="container mx-auto flex items-center justify-center gap-3">
              <AlertTriangle size={18} fill="white" className="text-transparent" />
              <span className="font-bold text-sm tracking-wide">{globalAlert.message}</span>
           </div>
           <button onClick={() => setGlobalAlert(null)} className="absolute right-4 text-white/80 hover:text-white">
              <X size={18} />
           </button>
        </div>
     );
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-kph-light flex items-center justify-center">
        <SEO title="Loading... | KPH News" description="Please wait while we load the latest Kwara news." />
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-12 h-12 text-kph-red animate-spin" />
          <p className="text-kph-charcoal font-bold animate-pulse">Loading Kwara News...</p>
        </div>
      </div>
    );
  }

  if (error || articles.length === 0) {
    return (
      <div className="min-h-screen bg-kph-light flex items-center justify-center p-4">
        <SEO title="No News | KPH News" description="No news articles found." />
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full text-center">
          <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4">
             <AlertTriangle className="w-8 h-8 text-kph-red" />
          </div>
          <h2 className="text-xl font-bold text-kph-charcoal mb-2">{error ? "Error Loading News" : "No News Available"}</h2>
          <button 
            onClick={fetchNews}
            className="flex items-center justify-center gap-2 w-full bg-kph-red text-white font-bold py-3 rounded-lg hover:bg-red-900 transition-colors"
          >
            <RefreshCw size={18} /> Retry
          </button>
        </div>
      </div>
    );
  }

  const featuredArticle = articles[0];
  const subFeaturedArticles = articles.slice(1, 3);
  const feedArticles = articles.slice(3, 10);

  const displayPolitics = articles.filter(a => 
    (a.category && a.category.toLowerCase().includes('politic'))
  ).slice(0, 3);

  const adConfig = AdminService.getAdConfig();

  return (
    <div className="bg-kph-light min-h-screen pb-12 animate-fade-in flex flex-col">
      <SEO 
        title="KPH News - Kwara Political Hangout | Home" 
        description="The #1 source for political news in Kwara State."
      />

      <GlobalAlertBanner />

      <div className="bg-kph-red text-white text-xs lg:text-sm py-2 overflow-hidden relative z-20 border-b border-red-900 shadow-md">
         <div className="container mx-auto px-4 lg:px-8 flex items-center">
            <span className="font-bold uppercase tracking-wider text-[10px] lg:text-xs bg-white/20 px-3 py-1 rounded mr-4 flex items-center gap-1 shrink-0">
               <Zap size={12} className="fill-current" /> Breaking
            </span>
            <div className="overflow-hidden flex-1 relative h-6 flex items-center group">
               <div className="absolute whitespace-nowrap animate-marquee group-hover:[animation-play-state:paused] flex items-center">
                  {articles.slice(0, 5).map((a, i) => (
                      <Link key={i} to={`/article/${a.id}`} className="mr-12 font-medium opacity-90 hover:opacity-100 flex items-center gap-3 cursor-pointer">
                         <span className="w-1.5 h-1.5 bg-white/60 rounded-full"></span> {a.title}
                      </Link>
                  ))}
               </div>
            </div>
         </div>
      </div>

      <section className="bg-kph-charcoal py-6 lg:py-12 relative overflow-hidden">
        <div className="container mx-auto px-4 lg:px-8 relative z-10">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 lg:h-[550px]">
            {featuredArticle && (
              <div className="lg:col-span-3 relative group overflow-hidden rounded-2xl h-[450px] lg:h-auto shadow-2xl">
                <Link to={`/article/${featuredArticle.id}`} className="block w-full h-full">
                  <img src={featuredArticle.imageUrl} alt={featuredArticle.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1.5s]" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/95 via-black/40 to-transparent"></div>
