      </section>

      {adConfig.homeBanner.enabled && adConfig.homeBanner.imageUrl && (
         <div className="container mx-auto px-4 lg:px-8 py-8">
            <a href={adConfig.homeBanner.linkUrl} className="block relative overflow-hidden rounded-2xl shadow-sm">
               <img src={adConfig.homeBanner.imageUrl} alt={adConfig.homeBanner.altText} className="w-full h-32 lg:h-40 object-cover" />
