const LockScreen = ({ onUnlock }: { onUnlock: () => void }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const handleUnlock = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') { 
      onUnlock();
    } else {
      setError(true);
      setPin('');
    }
  };

  return (
    <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
      <div className="w-full max-w-sm">
        <div className="text-center mb-10">
            <div className="w-24 h-24 bg-gray-900 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl border border-gray-800 animate-pulse-slow">
              <Shield size={48} className="text-kph-red" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">Super Admin</h2>
            <p className="text-gray-500 text-sm">System Access Restricted</p>
        </div>

        <form onSubmit={handleUnlock} className="space-y-6">
           <div>
               <label className="block text-xs font-bold text-gray-500 uppercase tracking-widest mb-2 text-center">Security PIN</label>
               <input 
                type="password" 
                value={pin}
                onChange={(e) => { setPin(e.target.value); setError(false); }}
                className={`w-full bg-gray-900 border-2 ${error ? 'border-red-500 text-red-500' : 'border-gray-800 text-white focus:border-kph-red'} rounded-2xl px-4 py-5 text-center text-3xl tracking-[1em] focus:outline-none transition-all duration-300 placeholder-gray-800 font-mono shadow-inner`}
                placeholder="••••"
                maxLength={4}
                autoFocus
                inputMode="numeric"
               />
           </div>

           {error && (
               <div className="flex items-center justify-center gap-2 text-red-500 text-sm font-bold animate-slide-down">
                   <AlertTriangle size={16} />
                   <span>Access Denied</span>
               </div>
           )}

           <button className="w-full bg-kph-red text-white font-bold py-4 rounded-2xl hover:bg-red-700 transition-all shadow-lg shadow-red-900/10 active:scale-95 transform duration-200">
             Unlock Console
           </button>
        </form>
      </div>
    </div>
  );
};

