const express = require('express');
const cors = require('cors');
const bodyParser = require('body-parser');

const app = express();
const PORT = 3000;

app.use(cors());
app.use(bodyParser.json());

// Mock Database (In-Memory for demo, usually a DB like MongoDB or PostgreSQL)
let db = {
  ads: {
    homeBanner: { enabled: false, imageUrl: '', linkUrl: '#', altText: 'KPH Banner' },
    sidebarAd: { enabled: false, imageUrl: '', linkUrl: '#', altText: 'Sidebar Ad' }
  },
  users: [],
  globalAlert: null,
  featuredArticleIds: [],
  writerArticles: [],
  messages: [],
  subscribers: []
};

// --- Routes ---

// Ads
app.get('/api/ads', (req, res) => res.json(db.ads));
app.post('/api/ads', (req, res) => {
  db.ads = req.body;
  res.json({ success: true, ads: db.ads });
});

// Users
app.get('/api/users', (req, res) => res.json(db.users));
app.post('/api/users', (req, res) => {
  const newUser = { ...req.body, id: Date.now().toString() };
  db.users.push(newUser);
  res.json(newUser);
});
app.put('/api/users/:id', (req, res) => {
  const { id } = req.params;
  const index = db.users.findIndex(u => u.id === id);
  if (index !== -1) {
    db.users[index] = { ...db.users[index], ...req.body };
    res.json(db.users[index]);
  } else {
    res.status(404).json({ error: 'User not found' });
  }
});
app.delete('/api/users/:id', (req, res) => {
  db.users = db.users.filter(u => u.id !== req.params.id);
  res.json({ success: true });
});

// Global Alert
app.get('/api/alert', (req, res) => res.json(db.globalAlert));
app.post('/api/alert', (req, res) => {
  db.globalAlert = req.body;
  res.json({ success: true });
});

// Featured
app.get('/api/featured', (req, res) => res.json(db.featuredArticleIds));
app.post('/api/featured', (req, res) => {
  const { articleId } = req.body;
  db.featuredArticleIds = [articleId, ...db.featuredArticleIds.filter(id => id !== articleId)];
  res.json(db.featuredArticleIds);
});

// Writer Articles
app.get('/api/articles', (req, res) => res.json(db.writerArticles));
app.post('/api/articles', (req, res) => {
  const article = { ...req.body, id: Date.now() };
  db.writerArticles.unshift(article);
  res.json(article);
});

app.listen(PORT, () => {
  console.log(`KPH Backend running on http://localhost:${PORT}`);
});

/**
 * Cloudinary Upload Service
 * Handles image and video uploads to Cloudinary
 */

const CLOUDINARY_UPLOAD_PRESET = 'kph_news_preset'; // Replace with your actual preset
const CLOUDINARY_CLOUD_NAME = 'kph-media'; // Replace with your actual cloud name

export const UploadService = {
  /**
   * Uploads a file to Cloudinary using unsigned upload preset
   */
  async uploadMedia(file: File): Promise<string> {
    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', CLOUDINARY_UPLOAD_PRESET);

    try {
      const response = await fetch(
        `https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD_NAME}/image/upload`,
        {
          method: 'POST',
          body: formData,
        }
      );

      if (!response.ok) {
        throw new Error('Upload failed');
      }

      const data = await response.json();
      return data.secure_url;
    } catch (error) {
      console.error('Cloudinary Upload Error:', error);
      // Fallback for demo: if Cloudinary not configured, return a local object URL
      return URL.createObjectURL(file);
    }
  }
};

