import { GoogleGenAI } from "@google/genai";
import { Article } from '../types';

// Guideline: Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Caching System ---
const CACHE_DURATION = 15 * 60 * 1000; // 15 minutes
interface CacheEntry {
  timestamp: number;
  data: Article[];
}
const newsCache: Record<string, CacheEntry> = {};
const articleDetailCache: Map<string, Article> = new Map();

// --- Helper Functions ---

function getContextualImage(title: string, category: string, index: number): string {
  const t = title.toLowerCase();
  const c = category.toLowerCase();
  let seed = `kwara_general_${index}`;

  if (t.includes('governor') || t.includes('abdulrazaq') || t.includes('executive')) seed = 'governor_speech';
  else if (t.includes('assembly') || t.includes('lawmaker') || t.includes('bill') || t.includes('legislat')) seed = 'legislation_hall';
  else if (t.includes('road') || t.includes('bridge') || t.includes('construct') || t.includes('project')) seed = 'construction_site';
  else if (t.includes('school') || t.includes('education') || t.includes('university') || t.includes('student')) seed = 'education_learning';
  else if (t.includes('health') || t.includes('hospital') || t.includes('clinic') || t.includes('doctor')) seed = 'medical_health';
  else if (t.includes('police') || t.includes('security') || t.includes('arrest') || t.includes('court')) seed = 'justice_security';
  else if (t.includes('sport') || t.includes('football') || t.includes('match')) seed = 'sports_action';
  else if (t.includes('budget') || t.includes('naira') || t.includes('economy') || t.includes('fund')) seed = 'economy_finance';
  else if (c.includes('politic')) seed = 'politics_vote';
  else if (c.includes('media')) seed = 'journalism_news';

  const dateStr = new Date().toISOString().split('T')[0];
  return `https://picsum.photos/seed/${seed}_${dateStr}_${index}/800/600`;
}

function parseGeminiResponse(text: string, category: string): Article[] {
  const articles: Article[] = [];
  const itemRegex = /<NEWS_ITEM>([\s\S]*?)<\/NEWS_ITEM>/g;
  let match;
  let index = 0;

  while ((match = itemRegex.exec(text)) !== null) {
    const block = match[1];

    const extract = (tag: string) => {
      const r = new RegExp(`<${tag}>([\\s\\S]*?)<\/${tag}>`, 'i');
      const m = block.match(r);
      return m ? m[1].trim() : '';
    };

    const title = extract('HEADLINE').replace(/^"/, '').replace(/"$/, '');
    const summary = extract('SUMMARY');
    const content = extract('CONTENT');
    const date = extract('DATE') || new Date().toLocaleDateString();
    const sourceUrl = extract('SOURCE_URL');
    const author = extract('AUTHOR') || 'KPH Staff';
    const fetchedImageUrl = extract('IMAGE_URL');

    if (title && summary) {
      const id = `gen_${Date.now()}_${index}`;

      let imageUrl = fetchedImageUrl;
      if (!imageUrl || !imageUrl.match(/^https?:\/\/.+/i)) {
        imageUrl = getContextualImage(title, category, index);
      }

      const article: Article = {
        id,
        title,
        excerpt: summary,
        content: content.length > 50 ? content : `<p>${summary}</p><p>Read more at the source.</p>`,
        category: category === 'General' ? 'News' : category,
        author,
        date,
        readTime: `${Math.ceil(summary.length / 200) + 1} min read`,
        imageUrl,
        sourceUrl,
        sourceName: sourceUrl ? new URL(sourceUrl).hostname.replace('www.', '') : 'Kwara News'
      };

      articles.push(article);
      articleDetailCache.set(id, article);
      index++;
    }
  }
  return articles;
}

function buildPrompt(topic: string, isSearch: boolean): string {
  const baseContext = isSearch 
    ? `You are a specialized news aggregator for Kwara State, Nigeria. Search for the following query: "${topic}".`
    : `You are a specialized news aggregator for Kwara State, Nigeria. Find the latest and most relevant news articles regarding "${topic}" in Kwara State from the last 7 days.`;

  return `
    ${baseContext}

    Strictly adhere to this output format. Do not include any conversational text.
    For each news item found, output a block like this:

    <NEWS_ITEM>
      <HEADLINE>Insert Headline Here</HEADLINE>
      <SUMMARY>Insert a 2-sentence summary here.</SUMMARY>
      <CONTENT>
        <p>Insert a structured HTML version of the story here. Use <h3> for subheadings.</p>
        <p>Ensure it is detailed enough for a full article view.</p>
      </CONTENT>
      <DATE>Insert Date (e.g., Oct 24, 2023)</DATE>
      <AUTHOR>Insert Author or Publisher Name</AUTHOR>
      <SOURCE_URL>Insert the URL of the source found</SOURCE_URL>
      <IMAGE_URL>Insert the og:image or main image URL found on the page. If none, leave empty.</IMAGE_URL>
    </NEWS_ITEM>

    Provide at least 6 distinct news items.
    Focus on credibility and local relevance to Kwara State (Ilorin, Offa, etc).
  `;
}

async function fetchRSSNews(topic: string): Promise<Article[]> {
  try {
    const query = encodeURIComponent(`Kwara State ${topic === 'General' ? '' : topic}`);
    const rssUrl = `https://news.google.com/rss/search?q=${query}&hl=en-NG&gl=NG&ceid=NG:en`;
    const proxyUrl = `https://api.rss2json.com/v1/api.json?rss_url=${encodeURIComponent(rssUrl)}`;

    const response = await fetch(proxyUrl);
    const json = await response.json();

    if (json.status !== 'ok') {
      return [];
    }

    return json.items.map((item: any, index: number) => {
      let imageUrl = '';
      const description = item.description || '';
      const imgMatch = description.match(/<img[^>]+src="([^">]+)"/);
      if (imgMatch && imgMatch[1]) {
        imageUrl = imgMatch[1];
      } 
      else if (item.enclosure && item.enclosure.link) {
        imageUrl = item.enclosure.link;
      } 
      else if (item.thumbnail) {
        imageUrl = item.thumbnail;
      }

      if (!imageUrl || imageUrl.includes('news.google.com')) {
        imageUrl = getContextualImage(item.title, topic, index);
      }

      const cleanExcerpt = description.replace(/<[^>]*>?/gm, '').substring(0, 150) + '...';
      const id = `rss_${Date.now()}_${index}`;

      const article: Article = {
        id: id,
        title: item.title,
        excerpt: cleanExcerpt,
        content: item.content || `<p>${description}</p><p>Read more at <a href="${item.link}" target="_blank">the original source</a>.</p>`,
        category: topic === 'General' ? 'News' : topic,
        author: item.author || 'Kwara News Feed',
        date: new Date(item.pubDate).toLocaleDateString(),
        readTime: '3 min read',
        imageUrl: imageUrl,
        sourceUrl: item.link,
        sourceName: 'Google News'
      };

      articleDetailCache.set(id, article);
      return article;
    });

  } catch (error) {
    console.error("RSS Error:", error);
    return [];
  }
}

export const NewsService = {

  async getLatestNews(topic: string = 'General'): Promise<Article[]> {
    const cacheKey = `latest_${topic}`;
    const cached = newsCache[cacheKey];
    if (cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
      return cached.data;
    }

    let articles: Article[] = [];

    const rssArticles = await fetchRSSNews(topic);
    if (rssArticles.length > 0) {
        articles = rssArticles;
    }

    if (articles.length < 3) {
      try {
        const prompt = buildPrompt(topic, false);
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: prompt,
          config: {
            tools: [{ googleSearch: {} }]
          }
        });

        if (response.text) {
          const geminiArticles = parseGeminiResponse(response.text, topic);
          const existingTitles = new Set(articles.map(a => a.title.toLowerCase()));
          geminiArticles.forEach(ga => {
            if (!existingTitles.has(ga.title.toLowerCase())) {
                articles.push(ga);
            }
          });
        }
      } catch (error) {
        console.error("Gemini News Fetch Error:", error);
      }
    }

    if (articles.length === 0) {
       return [];
    }

    newsCache[cacheKey] = {
      timestamp: Date.now(),
      data: articles
    };

    return articles;
  },

  async getArticleById(id: string): Promise<Article | undefined> {
    return articleDetailCache.get(id);
  },

  async searchNews(query: string): Promise<Article[]> {
     try {
       const prompt = buildPrompt(query, true);
       const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: prompt,
          config: {
             tools: [{ googleSearch: {} }]
          }
       });

       if (response.text) {
          const results = parseGeminiResponse(response.text, 'Search');
          results.forEach(a => articleDetailCache.set(a.id, a));
          return results;
       }
       return [];
     } catch (e) {
       console.error("Search Error", e);
       return [];
     }
  }
};

