export const AdminService = {
  // --- Generic Fetch Helper ---
  async callApi(path: string, method: string = 'GET', body?: any) {
    try {
      const options: RequestInit = {
        method,
        headers: { 'Content-Type': 'application/json' },
      };
      if (body) options.body = JSON.stringify(body);

      const response = await fetch(`${API_BASE_URL}${path}`, options);
      if (!response.ok) throw new Error('API request failed');
      return await response.json();
    } catch (e) {
      console.warn(`Backend not available for ${path}, using localStorage fallback.`);
      return this.localStorageFallback(path, method, body);
    }
  },

  // Fallback to maintain functionality if server is not running
  localStorageFallback(path: string, method: string, body: any) {
    const key = `kph_${path.replace(/\//g, '_')}`;
    if (method === 'GET') {
      const stored = localStorage.getItem(key);
      if (path === '/ads') return stored ? JSON.parse(stored) : DEFAULT_AD_CONFIG;
      if (path === '/featured') return stored ? JSON.parse(stored) : [];
      return stored ? JSON.parse(stored) : [];
    } else {
      localStorage.setItem(key, JSON.stringify(body));
      return body;
    }
  },

  // --- Ads ---
  async getAdConfig(): Promise<AdConfig> {
    return this.callApi('/ads');
  },

  async saveAdConfig(config: AdConfig) {
    return this.callApi('/ads', 'POST', config);
  },

  // --- Featured Articles ---
  async getFeaturedArticleIds(): Promise<string[]> {
    return this.callApi('/featured');
  },

  async setFeaturedArticle(articleId: string) {
    return this.callApi('/featured', 'POST', { articleId });
  },

  // --- Global Alert ---
  async getGlobalAlert(): Promise<GlobalAlert | null> {
    return this.callApi('/alert');
  },

  async setGlobalAlert(alert: GlobalAlert | null) {
    return this.callApi('/alert', 'POST', alert);
  },

  // --- User Management ---
  async getUsers(): Promise<User[]> {
    return this.callApi('/users');
  },

  async addUser(user: Omit<User, 'id' | 'joinedDate'>) {
    return this.callApi('/users', 'POST', {
      ...user,
      joinedDate: new Date().toISOString().split('T')[0],
      status: 'Active'
    });
  },

  async updateUserRole(userId: string, newRole: User['role'], newStatus: User['status']) {
    return this.callApi(`/users/${userId}`, 'PUT', { role: newRole, status: newStatus });
  },

  async deleteUser(userId: string) {
    return this.callApi(`/users/${userId}`, 'DELETE');
  },

  // --- Writer Articles ---
  async getWriterArticles(): Promise<WriterArticle[]> {
    return this.callApi('/articles');
  },

  async publishArticle(article: Omit<WriterArticle, 'id' | 'date' | 'views'>) {
    return this.callApi('/articles', 'POST', {
      ...article,
      date: new Date().toLocaleDateString(),
      views: '0'
    });
  },

  // --- Subscribers ---
  async addSubscriber(email: string) {
    return this.callApi('/subscribers', 'POST', { email });
  },

  // --- Messages ---
  async addMessage(message: Omit<Message, 'id' | 'date' | 'read'>) {
    return this.callApi('/messages', 'POST', {
      ...message,
      id: Date.now().toString(),
      date: new Date().toISOString(),
      read: false
    });
  }
};

