    setLoading(true);
    setError(null);
    try {
      // Fix: Await the asynchronous call to getGlobalAlert
      const alertConfig = await AdminService.getGlobalAlert();
      if (alertConfig && alertConfig.enabled) {
          setGlobalAlert(alertConfig);
