/**
 * Cloudinary Upload Service
 * Securely handles image uploads via backend proxy
 */

const API_BASE_URL = 'http://localhost:3000/api';

export const UploadService = {
  /**
   * Uploads a file through the Express backend to ensure secure signing
   */
  async uploadMedia(file: File): Promise<string> {
    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch(`${API_BASE_URL}/upload`, {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Cloudinary upload failed via proxy');
      }

      const data = await response.json();
      return data.url; // The secure_url from Cloudinary
    } catch (error) {
      console.error('UploadService Error:', error);
      // Fallback: Object URL for session-only preview if backend is unreachable
      return URL.createObjectURL(file);
    }
  }
};

