const API_BASE_URL = 'http://localhost:3000/api';

export interface AdConfig {
  homeBanner: {
    enabled: boolean;
    imageUrl: string;
    linkUrl: string;
    altText: string;
  };
  sidebarAd: {
    enabled: boolean;
    imageUrl: string;
    linkUrl: string;
    altText: string;
  };
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: 'Admin' | 'Editor' | 'Writer' | 'Suspended';
  joinedDate: string;
  status: 'Active' | 'Pending' | 'Banned';
}

export interface GlobalAlert {
  enabled: boolean;
  message: string;
  type: 'info' | 'warning' | 'critical';
}

const DEFAULT_AD_CONFIG: AdConfig = {
  homeBanner: { enabled: false, imageUrl: '', linkUrl: '#', altText: 'Advertisement' },
  sidebarAd: { enabled: false, imageUrl: '', linkUrl: '#', altText: 'Sidebar Advertisement' }
};

export const AdminService = {
  async callApi(path: string, method: string = 'GET', body?: any) {
    const options: RequestInit = {
      method,
      headers: { 'Content-Type': 'application/json' },
    };
    if (body) options.body = JSON.stringify(body);

    try {
      const response = await fetch(`${API_BASE_URL}${path}`, options);
      if (!response.ok) throw new Error(`API Error: ${response.statusText}`);
      return await response.json();
    } catch (e) {
      console.error(`Backend call to ${path} failed:`, e);
      // Return defaults/null to prevent crash if backend is starting up
      if (path === '/ads') return DEFAULT_AD_CONFIG;
      if (path === '/users' || path === '/featured') return [];
      return null;
    }
  },

  // --- Ads ---
  async getAdConfig(): Promise<AdConfig> {
    return this.callApi('/ads');
  },

  async saveAdConfig(config: AdConfig) {
    return this.callApi('/ads', 'POST', config);
  },

  // --- Featured Articles ---
  async getFeaturedArticleIds(): Promise<string[]> {
    return this.callApi('/featured');
  },

  async setFeaturedArticle(articleId: string, isFeatured: boolean = true) {
    return this.callApi('/featured', 'POST', { articleId, isFeatured });
  },

  // --- Global Alert ---
  async getGlobalAlert(): Promise<GlobalAlert | null> {
    return this.callApi('/alert');
  },

  async setGlobalAlert(alert: GlobalAlert | null) {
    return this.callApi('/alert', 'POST', alert);
  },

  // --- User Management ---
  async getUsers(): Promise<User[]> {
    return this.callApi('/users');
  },

  async addUser(user: Partial<User>) {
    return this.callApi('/users', 'POST', {
      ...user,
      joinedDate: new Date().toISOString(),
      status: 'Active'
    });
  },

  async updateUserRole(userId: string, newRole: User['role'], newStatus: User['status']) {
    return this.callApi(`/users/${userId}`, 'PUT', { role: newRole, status: newStatus });
  },

  async deleteUser(userId: string) {
    return this.callApi(`/users/${userId}`, 'DELETE');
  },

  // --- Messaging & Subs ---
  async addSubscriber(email: string) {
    return this.callApi('/subscribers', 'POST', { email });
  },

  async addMessage(message: any) {
    return this.callApi('/messages', 'POST', message);
  }
};

