  Settings, LogOut, Save, AlertTriangle, CheckCircle, 
  Search, Trash2, Globe, Server, Power, Plus, X, Menu, Upload, Loader2,
  ExternalLink
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { AdminService, AdConfig, User, GlobalAlert } from '../services/adminService';
import { UploadService } from '../services/uploadService';
import { NewsService } from '../services/newsService';
import { Article } from '../types';

const LockScreen = ({ onUnlock }: { onUnlock: () => void }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const handleUnlock = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '1234') onUnlock();
    else { setError(true); setPin(''); }
  };

  return (
    <div className="min-h-screen bg-gray-950 flex items-center justify-center p-4">
      <div className="w-full max-sm:max-w-xs max-w-sm">
        <div className="text-center mb-10">
            <div className="w-20 h-20 bg-gray-900 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl border border-gray-800 animate-pulse-slow">
              <Shield size={40} className="text-kph-red" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">Super Admin</h2>
            <p className="text-gray-500 text-sm">System Access Restricted</p>
        </div>
        <form onSubmit={handleUnlock} className="space-y-6">
           <input 
            type="password" value={pin} onChange={(e) => { setPin(e.target.value); setError(false); }}
            className={`w-full bg-gray-900 border-2 ${error ? 'border-red-500 text-red-500' : 'border-gray-800 text-white focus:border-kph-red'} rounded-2xl px-4 py-4 text-center text-3xl tracking-[1em] focus:outline-none font-mono shadow-inner`}
            placeholder="••••" maxLength={4} autoFocus inputMode="numeric"
           />
           {error && <div className="flex items-center justify-center gap-2 text-red-500 text-xs font-bold animate-slide-down"><AlertTriangle size={14} /> Access Denied</div>}
           <button className="w-full bg-kph-red text-white font-bold py-4 rounded-2xl hover:bg-red-700 transition-all shadow-lg shadow-red-900/10 active:scale-95">Unlock Console</button>
        </form>
      </div>
    </div>
  );
};

const AdminDashboard: React.FC = () => {
  const [locked, setLocked] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const navigate = useNavigate();

  // Data State
  const [users, setUsers] = useState<User[]>([]);
  const [adConfig, setAdConfig] = useState<AdConfig | null>(null);
  const [globalAlert, setGlobalAlert] = useState<GlobalAlert | null>(null);
  const [recentArticles, setRecentArticles] = useState<Article[]>([]);

  // UI State
  const [showAddUserModal, setShowAddUserModal] = useState(false);
  const [newUser, setNewUser] = useState({ name: '', email: '', role: 'Writer' });
  const [toast, setToast] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  useEffect(() => {
    if (!locked) {
      loadData();
    }
  }, [locked]);

  const loadData = async () => {
    try {
      const [u, ads, alert, news] = await Promise.all([
        AdminService.getUsers(),
        AdminService.getAdConfig(),
        AdminService.getGlobalAlert(),
        NewsService.getLatestNews()
      ]);
      setUsers(u || []);
      setAdConfig(ads);
      setGlobalAlert(alert);
      setRecentArticles(news || []);
    } catch (e) {
      console.error("Data Load Error:", e);
      showToast("Error syncing with Supabase. Using local cache.");
    }
  };

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, target: 'homeBanner' | 'sidebarAd') => {
    const file = e.target.files?.[0];
    if (!file || !adConfig) return;

    setIsUploading(target);
    try {
      const url = await UploadService.uploadMedia(file);
      setAdConfig({
        ...adConfig,
        [target]: { ...adConfig[target], imageUrl: url }
      });
      showToast('Media pushed to Cloudinary');
    } catch (e) {
      showToast('Upload failed. Try again.');
    } finally {
      setIsUploading(null);
    }
  };

  const handleSaveAds = async () => {
    if (adConfig) {
      await AdminService.saveAdConfig(adConfig);
      showToast('Advertisements synced successfully.');
    }
  };

  const handleUpdateUser = async (id: string, role: any, status: any) => {
    await AdminService.updateUserRole(id, role, status);
    loadData();
    showToast('User permissions updated.');
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm('Permanently delete this user access?')) {
        await AdminService.deleteUser(id);
        loadData();
        showToast('User removed from system.');
    }
  };

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newUser.name && newUser.email) {
        await AdminService.addUser(newUser as any);
        setShowAddUserModal(false);
        setNewUser({ name: '', email: '', role: 'Writer' });
        loadData();
        showToast('New system access created.');
    }
  };

  const handleFeatureArticle = async (id: string) => {
    await AdminService.setFeaturedArticle(id);
    showToast('Homepage hero updated.');
    loadData();
  };

  const handleSaveAlert = async () => {
    await AdminService.setGlobalAlert(globalAlert);
    showToast('Global alert broadcasted.');
  };

  if (locked) return <LockScreen onUnlock={() => setLocked(false)} />;

  return (
    <div className="min-h-screen bg-gray-50 flex font-sans text-gray-900">
      {toast && <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-slide-up border border-gray-700">
          <CheckCircle size={18} className="text-green-400" /> <span className="text-sm font-bold">{toast}</span>
      </div>}

      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-gray-900 text-gray-300 flex flex-col transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
         <div className="h-20 flex items-center px-6 border-b border-gray-800 text-white font-bold"><Shield className="mr-3 text-kph-red" size={24} /> ROOT CONSOLE</div>
         <nav className="flex-1 py-6 px-4 space-y-1">
            {[
              { id: 'dashboard', label: 'Overview', icon: Activity }, 
              { id: 'users', label: 'Team', icon: Users }, 
              { id: 'ads', label: 'Ads & Revenue', icon: DollarSign }, 
              { id: 'content', label: 'Promote', icon: Layout }, 
              { id: 'settings', label: 'System', icon: Settings }
            ].map(item => (
               <button key={item.id} onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }} className={`w-full flex items-center px-4 py-3.5 text-sm font-bold rounded-xl transition-all ${activeTab === item.id ? 'bg-kph-red text-white' : 'hover:bg-gray-800 hover:text-white'}`}>
                 <item.icon size={18} className="mr-3" /> {item.label}
               </button>
            ))}
         </nav>
         <div className="p-4 border-t border-gray-800"><button onClick={() => navigate('/')} className="w-full flex items-center justify-center gap-2 py-3 text-gray-400 hover:text-white"><LogOut size={16} /> Exit to Site</button></div>
      </aside>

      <main className="flex-1 lg:ml-72 flex flex-col min-h-screen">
         <header className="bg-white/80 backdrop-blur-md border-b px-8 h-20 flex items-center justify-between sticky top-0 z-30">
            <h1 className="text-xl font-bold uppercase tracking-tight">{activeTab}</h1>
            <div className="text-xs font-bold bg-green-50 text-green-700 px-3 py-1.5 rounded-full border border-green-100 flex items-center gap-2"><div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" /> CLOUD SYNC: READY</div>
         </header>

         {!adConfig ? (
            <div className="flex-1 flex items-center justify-center bg-gray-50">
              <div className="text-center space-y-4">
                 <Loader2 className="w-10 h-10 animate-spin text-kph-red mx-auto" />
                 <p className="font-bold text-gray-400">CONNECTING TO DATABASE...</p>
              </div>
            </div>
         ) : (
          <div className="p-8">
            {activeTab === 'dashboard' && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 animate-fade-in">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Active Users</p>
                  <p className="text-3xl font-black text-gray-900">{users.length}</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Ad Units</p>
                  <p className="text-3xl font-black text-gray-900">2</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Live News</p>
                  <p className="text-3xl font-black text-gray-900">{recentArticles.length}</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Alert Mode</p>
                  <p className={`text-3xl font-black ${globalAlert?.enabled ? 'text-red-600' : 'text-green-600'}`}>{globalAlert?.enabled ? 'ACTIVE' : 'OFF'}</p>
                </div>
              </div>
            )}

            {activeTab === 'ads' && (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-8 animate-fade-in">
                 <div className="space-y-6">
                    <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-200">
                       <h3 className="font-bold text-gray-900 mb-6 flex items-center gap-2"><Globe size={18} /> Homepage Banner</h3>
                       <div className="space-y-4">
                          <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                             <span className="text-sm font-bold">Visibility</span>
                             <button onClick={() => setAdConfig({...adConfig, homeBanner: {...adConfig.homeBanner, enabled: !adConfig.homeBanner.enabled}})} className={`w-12 h-6 rounded-full transition-colors ${adConfig.homeBanner.enabled ? 'bg-green-500' : 'bg-gray-300'} relative`}><div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${adConfig.homeBanner.enabled ? 'left-7' : 'left-1'}`} /></button>
                          </div>
                          <div className="flex gap-2">
                             <input type="text" value={adConfig.homeBanner.imageUrl} readOnly className="flex-1 border border-gray-200 rounded-xl px-4 py-3 text-sm bg-gray-50 text-gray-500 overflow-hidden" placeholder="No image found" />
                             <label className="bg-gray-900 text-white p-3 rounded-xl cursor-pointer hover:bg-black transition-colors shrink-0">
                                {isUploading === 'homeBanner' ? <Loader2 className="animate-spin" size={20} /> : <Upload size={20} />}
                                <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'homeBanner')} />
                             </label>
                          </div>
                          <input type="text" value={adConfig.homeBanner.linkUrl} onChange={(e) => setAdConfig({...adConfig, homeBanner: {...adConfig.homeBanner, linkUrl: e.target.value}})} className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:border-kph-red outline-none" placeholder="Destination URL (https://...)" />
                       </div>
                    </div>

                    <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-200">
                       <h3 className="font-bold text-gray-900 mb-6 flex items-center gap-2"><Layout size={18} /> Sidebar Box Ad</h3>
                       <div className="space-y-4">
                          <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                             <span className="text-sm font-bold">Visibility</span>
                             <button onClick={() => setAdConfig({...adConfig, sidebarAd: {...adConfig.sidebarAd, enabled: !adConfig.sidebarAd.enabled}})} className={`w-12 h-6 rounded-full transition-colors ${adConfig.sidebarAd.enabled ? 'bg-green-500' : 'bg-gray-300'} relative`}><div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${adConfig.sidebarAd.enabled ? 'left-7' : 'left-1'}`} /></button>
                          </div>
                          <div className="flex gap-2">
                             <input type="text" value={adConfig.sidebarAd.imageUrl} readOnly className="flex-1 border border-gray-200 rounded-xl px-4 py-3 text-sm bg-gray-50 text-gray-500 overflow-hidden" placeholder="No image found" />
                             <label className="bg-gray-900 text-white p-3 rounded-xl cursor-pointer hover:bg-black transition-colors shrink-0">
                                {isUploading === 'sidebarAd' ? <Loader2 className="animate-spin" size={20} /> : <Upload size={20} />}
                                <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'sidebarAd')} />
                             </label>
                          </div>
                          <input type="text" value={adConfig.sidebarAd.linkUrl} onChange={(e) => setAdConfig({...adConfig, sidebarAd: {...adConfig.sidebarAd, linkUrl: e.target.value}})} className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:border-kph-red outline-none" placeholder="Destination URL (https://...)" />
                       </div>
                    </div>

                    <button onClick={handleSaveAds} className="w-full bg-gray-900 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-black flex items-center justify-center gap-2 transition-all"><Save size={20} /> Commit to Supabase</button>
                 </div>

                 <div className="bg-gray-950 p-8 rounded-3xl text-white border border-gray-800 flex flex-col items-center gap-8 min-h-[600px] overflow-y-auto">
                    <div className="w-full">
                       <p className="text-xs font-bold text-gray-600 uppercase mb-4 text-center">Home Banner Live Preview</p>
                       {adConfig.homeBanner.imageUrl ? (
                          <div className="relative group rounded-xl overflow-hidden border border-gray-800 shadow-2xl bg-gray-900">
                             <img src={adConfig.homeBanner.imageUrl} className="w-full h-32 object-cover opacity-80" alt="Home Banner" />
                             <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity">
                                <a href={adConfig.homeBanner.linkUrl} target="_blank" rel="noopener noreferrer" className="p-2 bg-white text-gray-900 rounded-full hover:scale-110 transition-transform"><ExternalLink size={20} /></a>
                             </div>
                          </div>
                       ) : <div className="w-full h-32 border-2 border-dashed border-gray-800 flex items-center justify-center text-gray-700 font-bold uppercase text-xs rounded-xl">Pending Media</div>}
                    </div>

                    <div className="w-48">
                       <p className="text-xs font-bold text-gray-600 uppercase mb-4 text-center">Sidebar Live Preview</p>
                       {adConfig.sidebarAd.imageUrl ? (
