                             <img src={adConfig.sidebarAd.imageUrl} className="w-full h-64 object-cover opacity-80" alt="Sidebar Ad" />
                             <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity">
                                <a href={adConfig.sidebarAd.linkUrl} target="_blank" rel="noopener noreferrer" className="p-2 bg-white text-gray-900 rounded-full hover:scale-110 transition-transform"><ExternalLink size={20} /></a>
                             </div>
                          </div>
                       ) : <div className="w-full h-64 border-2 border-dashed border-gray-800 flex items-center justify-center text-gray-700 font-bold uppercase text-xs rounded-xl">Pending Media</div>}
                    </div>
                 </div>
              </div>
            )}

            {activeTab === 'users' && (
               <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden animate-fade-in min-h-[500px]">
                  <div className="p-6 border-b flex flex-col sm:flex-row justify-between items-center gap-4">
                     <div>
                        <h2 className="font-bold text-gray-900">Team Access Control</h2>
                        <p className="text-xs text-gray-500">Managing identities in Supabase auth table.</p>
                     </div>
                     <button onClick={() => setShowAddUserModal(true)} className="bg-gray-900 text-white px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-black transition-colors"><Plus size={18} /> New Access</button>
                  </div>
                  <div className="overflow-x-auto">
                     <table className="w-full">
                        <thead className="bg-gray-50 text-xs font-bold text-gray-400 uppercase tracking-wider">
                           <tr><th className="px-6 py-4 text-left">Member</th><th className="px-6 py-4 text-left">Role</th><th className="px-6 py-4 text-right">Action</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                           {users.map(u => (
                              <tr key={u.id} className="hover:bg-gray-50/50">
                                 <td className="px-6 py-4"><p className="font-bold text-sm text-gray-900">{u.name}</p><p className="text-xs text-gray-500">{u.email}</p></td>
