                           <span className="text-sm font-bold">Banner Live Status</span>
                           <button onClick={() => setGlobalAlert(prev => prev ? {...prev, enabled: !prev.enabled} : { enabled: true, message: 'Broadcast Message', type: 'info' })} className={`w-12 h-6 rounded-full transition-colors ${globalAlert?.enabled ? 'bg-red-500' : 'bg-gray-300'} relative`}><div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${globalAlert?.enabled ? 'left-7' : 'left-1'}`} /></button>
