                  <div><label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Email Address</label><input type="email" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} className="w-full border rounded-xl px-4 py-3 text-sm focus:border-kph-red outline-none bg-gray-50" required /></div>
                  <div className="flex gap-2 pt-4"><button type="button" onClick={() => setShowAddUserModal(false)} className="flex-1 bg-gray-100 font-bold py-3.5 rounded-xl">Cancel</button><button type="submit" className="flex-1 bg-kph-red text-white font-bold py-3.5 rounded-xl">Grant Access</button></div>
              </form>
          </div>
      </div>}
    </div>
  );
};

