import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { Clock, TrendingUp, ChevronRight, Loader2, AlertTriangle, RefreshCw, Zap, X } from 'lucide-react';
import Sidebar from '../components/Sidebar';
import { NewsService } from '../services/newsService';
import { AdminService, GlobalAlert, AdConfig } from '../services/adminService';
import { Article } from '../types';
import SEO from '../components/SEO';

const Home: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [globalAlert, setGlobalAlert] = useState<GlobalAlert | null>(null);
  const [adConfig, setAdConfig] = useState<AdConfig | null>(null);

  const fetchContent = async () => {
    setLoading(true);
    setError(null);
    try {
      // 1. Fetch System Settings from Supabase
      const [alertConfig, ads, featuredIds, newsData] = await Promise.all([
        AdminService.getGlobalAlert(),
        AdminService.getAdConfig(),
        AdminService.getFeaturedArticleIds(),
        NewsService.getLatestNews('General')
      ]);

      // Set Alert
      if (alertConfig && alertConfig.enabled) {
        setGlobalAlert(alertConfig);
      }

      // Set Ads
      setAdConfig(ads);

      // 2. Process News Feed with Promotion Logic
      let processedNews = [...newsData];
      if (featuredIds.length > 0) {
         // Sort so that featured articles from AI or Editorial appear first
         const topFeatureId = featuredIds[0];
         const featureIdx = processedNews.findIndex(a => a.id === topFeatureId);
         if (featureIdx > 0) {
            const item = processedNews.splice(featureIdx, 1)[0];
            processedNews.unshift(item);
         }
      }

      setArticles(processedNews);
    } catch (err: any) {
      console.error("Home Data Sync Error:", err);
      setError("Failed to synchronize with live news servers. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchContent();
  }, []);

  const GlobalAlertBanner = () => {
     if (!globalAlert) return null;

     const colors = {
        info: 'bg-blue-600',
        warning: 'bg-yellow-500',
        critical: 'bg-red-600'
     };

     return (
        <div className={`${colors[globalAlert.type]} text-white px-4 py-3 flex items-center justify-center relative animate-slide-down shadow-lg z-50 border-b border-black/10`}>
           <div className="container mx-auto flex items-center justify-center gap-3">
              <AlertTriangle size={18} fill="white" className="text-transparent" />
              <span className="font-bold text-sm tracking-wide text-center">{globalAlert.message}</span>
           </div>
           <button onClick={() => setGlobalAlert(null)} className="absolute right-4 text-white/80 hover:text-white p-1">
              <X size={18} />
           </button>
        </div>
     );
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-kph-light flex items-center justify-center">
        <SEO title="Syncing Live News... | KPH" description="Loading the latest political updates for Kwara State." />
        <div className="flex flex-col items-center gap-4 text-center px-4">
          <div className="relative">
            <Loader2 className="w-14 h-14 text-kph-red animate-spin" />
            <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-kph-red/20" size={20} />
          </div>
          <div className="space-y-1">
            <p className="text-kph-charcoal text-xl font-black tracking-tighter">KPH LIVE SYNC</p>
            <p className="text-gray-400 text-sm font-medium animate-pulse">Establishing secure connection to Kwara news servers...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error || articles.length === 0) {
    return (
      <div className="min-h-screen bg-kph-light flex items-center justify-center p-4">
        <SEO title="Connection Error | KPH" description="System unavailable." />
        <div className="bg-white p-10 rounded-3xl shadow-2xl max-w-md w-full text-center border border-red-50">
          <div className="w-20 h-20 bg-red-50 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-inner">
             <AlertTriangle className="w-10 h-10 text-kph-red" />
          </div>
          <h2 className="text-2xl font-black text-gray-900 mb-3">Sync Failed</h2>
          <p className="text-gray-500 mb-8 text-sm leading-relaxed">{error || "The news pipeline is currently undergoing maintenance. Please try again in a few moments."}</p>
          <button 
            onClick={fetchContent}
            className="flex items-center justify-center gap-3 w-full bg-gray-900 text-white font-bold py-4 rounded-2xl hover:bg-black transition-all shadow-xl active:scale-95"
          >
            <RefreshCw size={20} /> Force Re-sync
          </button>
        </div>
      </div>
    );
  }

  const featuredArticle = articles[0];
  const subFeaturedArticles = articles.slice(1, 3);
  const feedArticles = articles.slice(3, 10);

  return (
    <div className="bg-kph-light min-h-screen pb-12 animate-fade-in flex flex-col">
