            <div className="w-24 h-24 bg-gray-900 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-[0_0_50px_rgba(139,0,0,0.3)] border border-kph-red/30 group">
              <Shield size={48} className="text-kph-red group-hover:scale-110 transition-transform duration-500" />
            </div>
            <h2 className="text-4xl font-black text-white mb-3 tracking-tighter">KPH COMMAND</h2>
            <p className="text-gray-500 text-sm font-bold uppercase tracking-[0.2em]">Root Authorization Required</p>
        </div>
        <form onSubmit={handleUnlock} className="space-y-8">
           <div className="relative">
             <input 
              type="password" value={pin} onChange={(e) => { setPin(e.target.value); setError(false); }}
              className={`w-full bg-white/5 border-2 ${error ? 'border-red-500/50 text-red-500 shadow-[0_0_20px_rgba(239,68,68,0.2)]' : 'border-white/10 text-white focus:border-kph-red focus:bg-white/10'} rounded-3xl px-4 py-6 text-center text-4xl tracking-[1.5em] focus:outline-none font-mono transition-all duration-300 backdrop-blur-xl`}
