export const AdminService = {
  // --- Ads ---
  async getAdConfig(): Promise<AdConfig> {
    try {
      const { data, error } = await supabase.from('ads').select('*').eq('id', 1).maybeSingle();
      if (error) throw error;

      // Ensure nested properties exist via deep merging
      return {
        homeBanner: { ...DEFAULT_AD_CONFIG.homeBanner, ...(data?.homeBanner || {}) },
        sidebarAd: { ...DEFAULT_AD_CONFIG.sidebarAd, ...(data?.sidebarAd || {}) }
      };
    } catch (e) {
      console.warn("Supabase Ads unavailable, using local cache.");
      const cached = LocalDB.get('ads');
      return cached || DEFAULT_AD_CONFIG;
    }
  },

  async saveAdConfig(config: AdConfig) {
    try {
      const payload = {
        id: 1,
        homeBanner: config.homeBanner,
        sidebarAd: config.sidebarAd
      };
      const { error } = await supabase.from('ads').upsert(payload, { onConflict: 'id' });
      if (error) {
        console.error("Supabase Ads save failed:", error.message, "| Details:", error.details, "| Hint:", error.hint);
        throw error;
      }
    } catch (e: any) {
      console.error("Supabase Ads critical failure:", e.message || e);
    }
    LocalDB.set('ads', config);
  },

  // --- Featured Articles (Manual Editorial Picks) ---
  async getFeaturedArticleIds(): Promise<string[]> {
    try {
      const { data, error } = await supabase.from('featured_articles').select('article_id');
      if (error) throw error;
      return data ? data.map(i => i.article_id) : [];
    } catch (e) {
      return LocalDB.get('featured_ids') || [];
    }
  },

  async setFeaturedArticle(articleId: string, isFeatured: boolean = true) {
    try {
      if (isFeatured) {
        await supabase.from('featured_articles').upsert({ article_id: articleId });
      } else {
        await supabase.from('featured_articles').delete().eq('article_id', articleId);
      }
    } catch (e) {
      console.error("Supabase Featured update failed", e);
    }
    const current = LocalDB.get('featured_ids') || [];
    const updated = isFeatured ? [articleId] : current.filter((id: string) => id !== articleId);
    LocalDB.set('featured_ids', updated);
  },

  // --- Global Alert (Site-wide Banner) ---
  async getGlobalAlert(): Promise<GlobalAlert | null> {
    try {
      const { data, error } = await supabase.from('site_config').select('value').eq('key', 'global_alert').maybeSingle();
      if (error) throw error;
      return data?.value || null;
    } catch (e) {
      return LocalDB.get('global_alert');
    }
  },

  async setGlobalAlert(alert: GlobalAlert | null) {
    try {
      const { error } = await supabase.from('site_config').upsert({ key: 'global_alert', value: alert });
      if (error) throw error;
    } catch (e: any) {
      console.error("Supabase Alert save failed:", e.message || e);
    }
    LocalDB.set('global_alert', alert);
  },

  // --- User Management ---
  async getUsers(): Promise<User[]> {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      return data || [];
    } catch (e) {
      return LocalDB.get('users') || [];
    }
  },

  async addUser(user: Partial<User>) {
    const newUser = {
      ...user,
      id: user.id || `u_${Date.now()}`,
      joinedDate: new Date().toISOString(),
      status: 'Active'
    };
    try {
      const { error } = await supabase.from('users').insert([newUser]);
      if (error) throw error;
    } catch (e: any) {
      console.error("Supabase User insert failed:", e.message || e);
    }
    const users = await this.getUsers();
    LocalDB.set('users', [...users, newUser]);
  },

  async deleteUser(userId: string) {
    try {
      const { error } = await supabase.from('users').delete().eq('id', userId);
      if (error) throw error;
    } catch (e: any) {
      console.error("Supabase User removal failed:", e.message || e);
    }
    const users = await this.getUsers();
    LocalDB.set('users', users.filter(u => u.id !== userId));
  },

  async updateUserRole(userId: string, role: string, status: string) {
    try {
      const { error } = await supabase.from('users').update({ role, status }).eq('id', userId);
      if (error) throw error;
    } catch (e: any) {
      console.error("Supabase User update failed:", e.message || e);
    }
    const users = await this.getUsers();
    LocalDB.set('users', users.map(u => u.id === userId ? { ...u, role, status } : u));
  },

  // --- Writer/Editorial Articles ---
  async getWriterArticles(): Promise<WriterArticle[]> {
    try {
      const { data, error } = await supabase.from('writer_articles').select('*').order('date', { ascending: false });
      if (error) throw error;
      return data || [];
    } catch (e) {
      return LocalDB.get('writer_articles') || [];
    }
  },

  async publishArticle(article: Partial<WriterArticle>) {
    const fullArticle = {
      ...article,
      id: article.id || `art_${Date.now()}`,
      date: new Date().toLocaleDateString(),
    };
    try {
      const { error } = await supabase.from('writer_articles').insert([fullArticle]);
      if (error) throw error;
    } catch (e: any) {
      console.error("Supabase Article push failed:", e.message || e);
    }
    const articles = await this.getWriterArticles();
    LocalDB.set('writer_articles', [fullArticle, ...articles]);
  },

  // --- Engagement ---
  async addSubscriber(email: string) {
    try {
      await supabase.from('subscribers').insert([{ email }]);
    } catch (e) {}
    const subs = LocalDB.get('subscribers') || [];
    LocalDB.set('subscribers', [...subs, email]);
  },

  async addMessage(message: any) {
    try {
      await supabase.from('messages').insert([message]);
    } catch (e) {}
    const msgs = LocalDB.get('messages') || [];
    LocalDB.set('messages', [...msgs, message]);
  }
};

/**
 * Cloudinary Direct Upload Service
 * Uses provided credentials to upload directly from frontend
 */

const CLOUD_NAME = 'dohuj4mx9';
const API_KEY = '884167539656433';
const API_SECRET = '8Avv4cnOYetWpmYtb8I5rgwv7KM';

export const UploadService = {
  /**
   * Generates a signature for signed uploads to Cloudinary
   * Cloudinary requires parameters to be sorted alphabetically and joined as key=value&key2=value2,
   * then appending the API_SECRET (no & before secret).
   */
  async generateSignature(params: Record<string, string>): Promise<string> {
    const sortedKeys = Object.keys(params).sort();
    const paramString = sortedKeys
      .map(key => `${key}=${params[key]}`)
      .join('&') + API_SECRET;

    const encoder = new TextEncoder();
    const data = encoder.encode(paramString);
    const hashBuffer = await window.crypto.subtle.digest('SHA-1', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  },

  async uploadMedia(file: File): Promise<string> {
    const timestamp = Math.round(new Date().getTime() / 1000).toString();
    const folder = 'kph_news';

    // Parameters to be signed
    const paramsToSign = {
      folder,
      timestamp,
    };

    try {
      const signature = await this.generateSignature(paramsToSign);

      const formData = new FormData();
      formData.append('file', file);
      formData.append('api_key', API_KEY);
      formData.append('timestamp', timestamp);
      formData.append('folder', folder);
      formData.append('signature', signature);

      console.log(`[Cloudinary] Initializing signed push for: ${file.name} to cloud: ${CLOUD_NAME}`);

      const response = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`, {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errData = await response.json();
        console.error("[Cloudinary] Server Rejected Request:", errData);
        throw new Error(errData.error?.message || 'Cloudinary handshaking failed');
      }

      const data = await response.json();
      console.log("[Cloudinary] Asset Synchronization Complete:", data.secure_url);
      return data.secure_url;
    } catch (error: any) {
      console.error('UploadService Critical Error:', error.message || error);
      // Fallback to local Blob URL so the application remains functional even if credentials are rejected
      return URL.createObjectURL(file);
    }
  }
};

