      await supabase.from('site_config').upsert({ key: 'global_alert', value: alert });
    } catch (e) {}
  },

  // --- User Management ---
  async getUsers(): Promise<User[]> {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      LocalDB.set('users', data || []);
      return data || [];
