  return (
    <div className="min-h-screen bg-[#0a0a0b] flex items-center justify-center p-4 selection:bg-kph-red selection:text-white">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-kph-red/10 via-transparent to-transparent opacity-50"></div>
      <div className="w-full max-w-sm relative z-10">
        <div className="text-center mb-12">
            <div className="w-24 h-24 bg-gray-900 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-[0_0_50px_rgba(139,0,0,0.3)] border border-kph-red/30 group">
              <Shield size={48} className="text-kph-red group-hover:scale-110 transition-transform duration-500" />
