const AdminDashboard: React.FC = () => {
  const [locked, setLocked] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const navigate = useNavigate();

  const [users, setUsers] = useState<User[]>([]);
  const [adConfig, setAdConfig] = useState<AdConfig | null>(null);
  const [globalAlert, setGlobalAlert] = useState<GlobalAlert | null>(null);
  const [recentArticles, setRecentArticles] = useState<Article[]>([]);

  const [showAddUserModal, setShowAddUserModal] = useState(false);
  const [newUser, setNewUser] = useState({ name: '', email: '', role: 'Writer' });
  const [toast, setToast] = useState<string | null>(null);
  const [isUploading, setIsUploading] = useState<string | null>(null);

  useEffect(() => {
    if (!locked) loadData();
  }, [locked]);

  const loadData = async () => {
    try {
      const [u, ads, alert, news] = await Promise.all([
        AdminService.getUsers(),
        AdminService.getAdConfig(),
        AdminService.getGlobalAlert(),
        NewsService.getLatestNews()
      ]);
      setUsers(u || []);
      setAdConfig(ads);
      setGlobalAlert(alert);
      setRecentArticles(news || []);
    } catch (e: any) {
      console.warn("Sync Interrupted. Command Console operating on local failover.");
      showToast("Network Unavailable. Local storage active.");
      if (!adConfig) setAdConfig(await AdminService.getAdConfig());
    }
  };

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, target: 'homeBanner' | 'sidebarAd') => {
    const file = e.target.files?.[0];
    if (!file || !adConfig) return;
    setIsUploading(target);
    try {
      const url = await UploadService.uploadMedia(file);
      setAdConfig(prev => prev ? ({ ...prev, [target]: { ...prev[target], imageUrl: url } }) : null);
      showToast('Asset deployed successfully.');
    } catch (e) {
      showToast('Media deployment failure.');
    } finally {
      setIsUploading(null);
    }
  };

  const handleSaveAds = async () => {
    if (adConfig) {
      await AdminService.saveAdConfig(adConfig);
      showToast('Global Ad Network synchronized.');
    }
  };

  const handleResetStats = async () => {
    if (confirm("Reset all click and impression data for this campaign?")) {
      await AdminService.resetAdStats();
      loadData();
      showToast("Metrics purged.");
    }
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm('Revoke system access for this member?')) {
        await AdminService.deleteUser(id);
        loadData();
        showToast('Member credentials purged.');
    }
  };

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newUser.name && newUser.email) {
        await AdminService.addUser(newUser as any);
        setShowAddUserModal(false);
        setNewUser({ name: '', email: '', role: 'Writer' });
        loadData();
        showToast('New system identity established.');
    }
  };

  const handleFeatureArticle = async (id: string) => {
    await AdminService.setFeaturedArticle(id);
    showToast('Homepage hero projection updated.');
    loadData();
  };

  const handleSaveAlert = async () => {
    await AdminService.setGlobalAlert(globalAlert);
    showToast('Emergency broadcast updated.');
  };

  const calculateCTR = (clicks: number, impressions: number) => {
    if (impressions === 0) return "0.00";
    return ((clicks / impressions) * 100).toFixed(2);
  };

  if (locked) return <LockScreen onUnlock={() => setLocked(false)} />;

  return (
    <div className="min-h-screen bg-[#f8f9fb] flex font-sans text-gray-900 selection:bg-kph-red selection:text-white">
      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-8 py-4 rounded-3xl shadow-xl flex items-center gap-4 animate-slide-up border border-white/10 backdrop-blur-xl">
          <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center shrink-0">
             <CheckCircle size={18} className="text-white" /> 
          </div>
          <span className="text-sm font-black uppercase tracking-wider">{toast}</span>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-80 bg-gray-950 text-gray-300 flex flex-col transition-transform duration-500 shadow-2xl ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
         <div className="h-24 flex items-center px-8 border-b border-white/5">
            <div className="w-10 h-10 bg-kph-red rounded-xl flex items-center justify-center mr-4 shadow-lg shadow-red-900/20">
               <Shield className="text-white" size={22} />
            </div>
            <div>
              <p className="text-white font-black text-lg tracking-tighter leading-none">COMMAND</p>
              <p className="text-[10px] text-gray-500 font-bold tracking-[0.3em] uppercase mt-1">Console v4.2</p>
            </div>
         </div>

         <nav className="flex-1 py-10 px-6 space-y-2">
            {[
              { id: 'dashboard', label: 'Network Overview', icon: Activity }, 
              { id: 'users', label: 'Identity Access', icon: Users }, 
              { id: 'ads', label: 'Campaign Ads', icon: DollarSign }, 
              { id: 'content', label: 'Content Strategy', icon: Layout }, 
              { id: 'settings', label: 'System Kernel', icon: Settings }
            ].map(item => (
               <button 
                key={item.id} 
                onClick={() => { setActiveTab(item.id); setIsSidebarOpen(false); }} 
                className={`w-full flex items-center px-5 py-4 text-sm font-bold rounded-2xl transition-all group ${activeTab === item.id ? 'bg-kph-red text-white shadow-xl shadow-red-900/20' : 'hover:bg-white/5 hover:text-white'}`}
               >
                 <item.icon size={20} className={`mr-4 transition-colors ${activeTab === item.id ? 'text-white' : 'text-gray-600 group-hover:text-white'}`} /> 
                 {item.label}
               </button>
            ))}
         </nav>

         <div className="p-6 border-t border-white/5">
            <button onClick={() => navigate('/')} className="w-full flex items-center justify-center gap-3 py-4 text-gray-500 hover:text-white font-bold text-sm transition-colors bg-white/5 rounded-2xl"><LogOut size={16} /> Terminate Session</button>
         </div>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
         <header className="bg-white/70 backdrop-blur-2xl border-b border-gray-100 px-10 h-24 flex items-center justify-between sticky top-0 z-30">
            <div className="flex items-center gap-4">
              <button onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 bg-gray-100 rounded-xl"><Menu size={20} /></button>
              <div>
                <h1 className="text-2xl font-black uppercase tracking-tighter text-gray-900">{activeTab}</h1>
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-0.5">Admin Console / Central Intelligence</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <div className="hidden md:flex items-center gap-2 bg-gray-100 px-4 py-2 rounded-2xl border border-gray-200">
                <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                <span className="text-[10px] font-black text-gray-600 uppercase tracking-wider">Cloud Engine Active</span>
              </div>
            </div>
         </header>

         {!adConfig ? (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center">
                 <Loader2 className="w-16 h-16 animate-spin text-kph-red mx-auto opacity-20 mb-6" />
                 <p className="font-black text-gray-400 uppercase tracking-[0.3em] text-xs">Accessing Command Interface...</p>
              </div>
            </div>
         ) : (
          <div className="p-10 max-w-[1600px] mx-auto w-full space-y-10 pb-20 overflow-y-auto">

            {activeTab === 'dashboard' && (
              <div className="space-y-10 animate-fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {[
                    { label: 'Network Readership', value: '42.8k', trend: '+12%', icon: Eye, color: 'text-blue-600', bg: 'bg-blue-50' },
                    { label: 'Active Identity Access', value: users.length, trend: 'Stable', icon: Users, color: 'text-purple-600', bg: 'bg-purple-50' },
                    { label: 'Ad Impressions', value: (adConfig.homeBanner.stats.impressions + adConfig.sidebarAd.stats.impressions).toLocaleString(), trend: '+4 today', icon: BarChart3, color: 'text-green-600', bg: 'bg-green-50' },
                    { label: 'Total Ad Clicks', value: (adConfig.homeBanner.stats.clicks + adConfig.sidebarAd.stats.clicks).toLocaleString(), trend: '+22%', icon: MousePointer2, color: 'text-amber-600', bg: 'bg-amber-50' }
                  ].map((stat, i) => (
                    <div key={i} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 group hover:shadow-xl transition-all duration-500">
                      <div className="w-14 h-14 ${stat.bg} ${stat.color} rounded-2xl flex items-center justify-center mb-6">
                        <stat.icon size={24} className={stat.color} />
                      </div>
                      <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest mb-1">{stat.label}</p>
                      <div className="flex items-baseline gap-3">
                        <p className="text-4xl font-black text-gray-900 tracking-tighter">{stat.value}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'ads' && adConfig && (
              <div className="grid grid-cols-1 xl:grid-cols-3 gap-10 animate-fade-in">
                 <div className="xl:col-span-2 space-y-8">
                    {/* Home Banner Control */}
                    <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100">
                       <div className="flex justify-between items-center mb-8">
                          <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter flex items-center gap-3"><Globe size={22} className="text-kph-red" /> Headline Banner Unit</h3>
                          <div className="flex items-center gap-4">
                             <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">CTR: {calculateCTR(adConfig.homeBanner.stats.clicks, adConfig.homeBanner.stats.impressions)}%</span>
                             <button 
                                onClick={() => setAdConfig(prev => prev ? ({...prev, homeBanner: {...prev.homeBanner, enabled: !prev.homeBanner.enabled}}) : null)} 
                                className={`w-14 h-7 rounded-full transition-all duration-300 ${(adConfig.homeBanner?.enabled) ? 'bg-green-500' : 'bg-gray-300'} relative`}
                             >
                                <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-all shadow-md ${(adConfig.homeBanner?.enabled) ? 'left-8' : 'left-1'}`} />
                             </button>
                          </div>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                          <div className="space-y-6">
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Ad Title (Internal)</label>
                                <input 
                                   type="text" 
                                   value={adConfig.homeBanner.title || ''} 
                                   onChange={(e) => setAdConfig(prev => prev ? ({...prev, homeBanner: {...prev.homeBanner, title: e.target.value}}) : null)} 
                                   className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none transition-all" 
                                   placeholder="e.g. November Election Promo" 
                                />
                             </div>
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Destination Link</label>
                                <input 
                                   type="text" 
                                   value={adConfig.homeBanner.linkUrl} 
                                   onChange={(e) => setAdConfig(prev => prev ? ({...prev, homeBanner: {...prev.homeBanner, linkUrl: e.target.value}}) : null)} 
                                   className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none transition-all" 
                                   placeholder="https://..." 
                                />
                             </div>
                          </div>
                          <div className="space-y-6">
                             <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Banner Creative</label>
                             <div className="relative group aspect-video bg-gray-50 rounded-[2.5rem] border-2 border-dashed border-gray-200 overflow-hidden flex items-center justify-center">
                                {adConfig.homeBanner.imageUrl ? (
                                   <>
                                      <img src={adConfig.homeBanner.imageUrl} className="w-full h-full object-cover" />
                                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                         <label className="bg-white text-gray-900 px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest cursor-pointer hover:scale-105 transition-transform">Replace Asset</label>
                                      </div>
                                   </>
                                ) : (
                                   <div className="text-center">
                                      <ImageIcon className="mx-auto text-gray-300 mb-2" size={32} />
                                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">No Image Configured</p>
                                   </div>
                                )}
                                <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'homeBanner')} />
                             </div>
                          </div>
                       </div>
                    </div>

                    {/* Sidebar Ad Control */}
                    <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100">
                       <div className="flex justify-between items-center mb-8">
                          <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter flex items-center gap-3"><Layout size={22} className="text-kph-red" /> Sidebar Intelligence Box</h3>
                          <div className="flex items-center gap-4">
                             <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">CTR: {calculateCTR(adConfig.sidebarAd.stats.clicks, adConfig.sidebarAd.stats.impressions)}%</span>
                             <button 
                                onClick={() => setAdConfig(prev => prev ? ({...prev, sidebarAd: {...prev.sidebarAd, enabled: !prev.sidebarAd.enabled}}) : null)} 
                                className={`w-14 h-7 rounded-full transition-all duration-300 ${(adConfig.sidebarAd?.enabled) ? 'bg-green-500' : 'bg-gray-300'} relative`}
                             >
                                <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-all shadow-md ${(adConfig.sidebarAd?.enabled) ? 'left-8' : 'left-1'}`} />
                             </button>
                          </div>
                       </div>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                          <div className="space-y-6">
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Ad Title</label>
                                <input 
                                   type="text" 
                                   value={adConfig.sidebarAd.title || ''} 
                                   onChange={(e) => setAdConfig(prev => prev ? ({...prev, sidebarAd: {...prev.sidebarAd, title: e.target.value}}) : null)} 
                                   className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none transition-all" 
                                />
                             </div>
                             <div className="space-y-2">
                                <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Destination Link</label>
                                <input 
                                   type="text" 
                                   value={adConfig.sidebarAd.linkUrl} 
                                   onChange={(e) => setAdConfig(prev => prev ? ({...prev, sidebarAd: {...prev.sidebarAd, linkUrl: e.target.value}}) : null)} 
                                   className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none transition-all" 
                                />
                             </div>
                          </div>
                          <div className="space-y-6">
                             <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Square Creative</label>
                             <div className="relative group aspect-square bg-gray-50 rounded-[2.5rem] border-2 border-dashed border-gray-200 overflow-hidden flex items-center justify-center">
                                {adConfig.sidebarAd.imageUrl ? (
                                   <>
                                      <img src={adConfig.sidebarAd.imageUrl} className="w-full h-full object-cover" />
                                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                         <label className="bg-white text-gray-900 px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest cursor-pointer hover:scale-105 transition-transform">Replace Asset</label>
                                      </div>
                                   </>
                                ) : (
                                   <div className="text-center">
                                      <ImageIcon className="mx-auto text-gray-300 mb-2" size={32} />
                                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">No Image</p>
                                   </div>
                                )}
                                <input type="file" className="hidden" accept="image/*" onChange={(e) => handleFileUpload(e, 'sidebarAd')} />
                             </div>
                          </div>
                       </div>
                    </div>
                 </div>

                 <div className="space-y-8">
                    <div className="bg-gray-950 p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden">
                       <div className="absolute top-0 right-0 w-32 h-32 bg-kph-red opacity-10 blur-3xl rounded-full -mr-16 -mt-16"></div>
                       <h3 className="text-xl font-black uppercase tracking-tighter mb-10 flex items-center gap-3"><Activity size={22} className="text-kph-red" /> Global Metrics</h3>

                       <div className="space-y-10">
                          <div className="space-y-4">
                             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">Headline Performance</p>
                             <PerformanceBar label="Impressions" value={adConfig.homeBanner.stats.impressions} total={adConfig.homeBanner.stats.impressions} />
                             <PerformanceBar label="Clicks" value={adConfig.homeBanner.stats.clicks} total={adConfig.homeBanner.stats.impressions} color="bg-kph-red" />
                          </div>
                          <div className="space-y-4">
                             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-500">Sidebar Performance</p>
                             <PerformanceBar label="Impressions" value={adConfig.sidebarAd.stats.impressions} total={adConfig.sidebarAd.stats.impressions} />
                             <PerformanceBar label="Clicks" value={adConfig.sidebarAd.stats.clicks} total={adConfig.sidebarAd.stats.impressions} color="bg-kph-red" />
                          </div>

                          <div className="pt-8 border-t border-white/10 space-y-4">
                             <button onClick={handleSaveAds} className="w-full bg-white text-gray-900 py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition-all flex items-center justify-center gap-3"><Save size={18} /> Sync Network</button>
                             <button onClick={handleResetStats} className="w-full bg-white/5 text-gray-400 py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:bg-white/10 transition-all flex items-center justify-center gap-3 border border-white/5"><RefreshCcw size={18} /> Reset Campaign Stats</button>
                          </div>
                       </div>
                    </div>
                 </div>
              </div>
            )}

            {activeTab === 'users' && (
               <div className="bg-white rounded-[3rem] shadow-sm border border-gray-100 overflow-hidden animate-fade-in">
                  <div className="p-10 border-b border-gray-50 flex flex-col sm:flex-row justify-between items-center gap-6 bg-gray-50/30">
                     <div>
                        <h2 className="text-2xl font-black text-gray-900 uppercase tracking-tighter">Team Identity Management</h2>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">Authorized access points for KPH internal systems</p>
                     </div>
                     <button onClick={() => setShowAddUserModal(true)} className="bg-gray-900 text-white px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center gap-3 hover:bg-black transition-all shadow-xl"><Plus size={18} /> Establish New Entry</button>
                  </div>
                  <div className="overflow-x-auto">
                     <table className="w-full border-collapse">
                        <thead className="bg-gray-50/50 text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] border-b border-gray-100">
                           <tr>
                             <th className="px-10 py-6 text-left">Internal ID</th>
                             <th className="px-10 py-6 text-left">System Persona</th>
                             <th className="px-10 py-6 text-left">Level</th>
                             <th className="px-10 py-6 text-right">Security</th>
                           </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                           {users.map(u => (
                              <tr key={u.id} className="hover:bg-gray-50 transition-colors group">
                                 <td className="px-10 py-8">
                                    <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-gray-100 rounded-2xl flex items-center justify-center font-black text-gray-400">
                                        {u.name.charAt(0)}
                                      </div>
                                      <div>
                                        <p className="text-sm font-black text-gray-900">{u.name}</p>
                                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">{u.email}</p>
                                      </div>
                                    </div>
                                 </td>
                                 <td className="px-10 py-8">
                                    <div className="flex items-center gap-2">
                                       <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                                       <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">Active Connection</span>
                                    </div>
                                 </td>
                                 <td className="px-10 py-8">
                                    <span className={`px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-[0.2em] ${u.role === 'Admin' ? 'bg-red-50 text-red-600' : 'bg-gray-100 text-gray-600'}`}>
                                      {u.role}
                                    </span>
                                 </td>
                                 <td className="px-10 py-8 text-right">
                                    <button onClick={() => handleDeleteUser(u.id)} className="text-gray-300 hover:text-red-600 p-3 rounded-xl hover:bg-red-50 transition-all opacity-0 group-hover:opacity-100"><Trash2 size={20} /></button>
                                 </td>
                              </tr>
                           ))}
                        </tbody>
                     </table>
                  </div>
               </div>
            )}
          </div>
         )}
      </div>

      {showAddUserModal && (
        <div className="fixed inset-0 bg-gray-950/80 backdrop-blur-xl flex items-center justify-center z-[100] p-6">
          <div className="bg-white rounded-[3.5rem] shadow-2xl p-12 w-full max-w-lg border border-gray-100 animate-slide-up relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-kph-red to-red-400"></div>
              <div className="flex items-center justify-between mb-10">
                 <div>
                   <h3 className="text-2xl font-black text-gray-900 uppercase tracking-tighter">System Entry</h3>
                   <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">Assigning new identity token</p>
                 </div>
                 <button onClick={() => setShowAddUserModal(false)} className="w-12 h-12 bg-gray-100 hover:bg-gray-200 text-gray-400 rounded-2xl transition-all flex items-center justify-center"><X size={24} /></button>
              </div>
              <form onSubmit={handleAddUser} className="space-y-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Full Identity Name</label>
                    <input type="text" value={newUser.name} onChange={e => setNewUser({...newUser, name: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none" required />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-4">Digital Mail Point</label>
                    <input type="email" value={newUser.email} onChange={e => setNewUser({...newUser, email: e.target.value})} className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-8 py-4 text-sm font-bold focus:border-kph-red outline-none" required />
                  </div>
                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => setShowAddUserModal(false)} className="flex-1 bg-gray-100 text-gray-500 font-black py-5 rounded-[2rem] text-[10px] uppercase tracking-widest">Abort</button>
                    <button type="submit" className="flex-2 flex-[2] bg-gray-900 text-white font-black py-5 rounded-[2rem] text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-xl">Authorize Entry</button>
                  </div>
              </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
